-- MARK CHAPTER 6 — Rejection, Mission, and Miracles Over Nature
-- 56 verses · Greek text · Word studies · Cross-refs
-- ═══════════════════════════════════════════════════

-- Step 1: Insert chapter metadata
INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 6,
  'Mark 6 is a chapter of sharp contrasts: rejection and reception, human weakness and divine power, death and abundance. It opens with Jesus'' rejection in his hometown Nazareth (vv.1-6a), where ''he could there do no mighty work'' because of their unbelief — one of the most startling statements in the Gospels. ''He marvelled because of their unbelief'' (v.6). Undeterred, Jesus sends the Twelve on their first independent mission, giving them authority over unclean spirits and instructing them to travel light, trusting in God''s provision (vv.6b-13). Mark then inserts a flashback explaining John the Baptist''s execution by Herod Antipas (vv.14-29) — the grim story of Herodias'' grudge, Salome''s dance, and the prophet''s beheading. When the apostles return from their mission, Jesus takes them to a deserted place for rest (vv.30-32), but the crowds anticipate them. Moved with compassion because they are ''as sheep not having a shepherd,'' Jesus teaches them and then miraculously feeds 5,000 men with five loaves and two fishes (vv.33-44). Twelve baskets of fragments remain — one for each apostle. Immediately Jesus sends the disciples across the sea and goes up a mountain to pray (vv.45-46). In the fourth watch of the night (3-6 AM), he comes to them walking on the sea, identifies himself with the divine formula ''It is I; be not afraid'' (egō eimi, v.50), and the wind ceases. Mark notes that ''they were sore amazed... for they considered not the miracle of the loaves: for their heart was hardened'' (vv.51-52). The chapter closes with a summary of healing ministry in Gennesaret (vv.53-56).',
  'Rejection and Revelation — The Servant King Feeds, Walks, and Heals',
  'σπλαγχνίζομαι (splanchnizomai)',
  'To be moved with compassion, to feel deep pity — from splanchna (the inner organs, viscera). In Mark 6:34, Jesus sees the shepherdless crowd and is ''moved with compassion'' — a visceral, gut-level response to human need. This compassion is not passive sentiment but active motivation: it drives him to teach (v.34) and feed (vv.35-44). Jesus'' compassion is the bridge between divine power and human need. The Servant King does not reign from a distance; he enters into human suffering with his whole being.',
  '["Rejection at Nazareth (vv.1-6): He came into his own country and his disciples follow him. Is not this the carpenter the son of Mary. A prophet is not without honour but in his own country and among his own kin. He could there do no mighty work save that he laid his hands upon a few sick folk. He marvelled because of their unbelief","The Mission of the Twelve (vv.6b-13): He called unto him the twelve and began to send them forth by two and two and gave them power over unclean spirits. Take nothing for your journey save a staff only. And they went out and preached that men should repent and cast out many devils and anointed with oil many that were sick and healed them","The Death of John the Baptist (vv.14-29): King Herod heard of him for his name was spread abroad. Herod feared John knowing that he was a just man and an holy. When Herodias daughter danced and pleased Herod she asked for the head of John the Baptist. He sent an executioner and commanded his head to be brought","Feeding the Five Thousand (vv.30-44): Come ye yourselves apart into a desert place and rest a while. He was moved with compassion toward them because they were as sheep not having a shepherd. Give ye them to eat. He took the five loaves and the two fishes and blessed and brake and gave. They did all eat and were filled. They that did eat of the loaves were about five thousand men","Walking on the Sea and Gennesaret Healings (vv.45-56): He went unto them walking upon the sea. Be of good cheer it is I be not afraid. The wind ceased and they were sore amazed for they considered not the miracle of the loaves for their heart was hardened. Whithersoever he entered into villages or cities or country they laid the sick in the streets and as many as touched him were made whole"]'
FROM books b WHERE b.name = 'Mark';

-- Step 2: Insert all 56 verses
INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And he went out from thence, and came into his own country; and his disciples follow him.',
   'Καὶ ἐξῆλθεν ἐκεῖθεν καὶ ἦλθεν εἰς τὴν πατρίδα αὐτοῦ καὶ ἀκολουθοῦσιν αὐτῷ οἱ μαθηταὶ αὐτοῦ',
   'Kai exēlthen ekeithen kai ēlthen eis tēn patrida autou kai akolouthousin autō hoi mathētai autou',
   '''His own country'' (tēn patrida autou — his hometown; Nazareth, where he grew up). ''His disciples follow him'' — Jesus returns home not alone but with an entourage of followers, which would have been conspicuous in a small village. The visit tests whether his hometown will respond differently from the crowds elsewhere.',
   NULL),
  (2, 'And when the sabbath day was come, he began to teach in the synagogue: and many hearing him were astonished, saying, From whence hath this man these things? and what wisdom is this which is given unto him, that even such mighty works are wrought by his hands?',
   'καὶ γενομένου σαββάτου ἤρξατο ἐν τῇ συναγωγῇ διδάσκειν καὶ πολλοὶ ἀκούοντες ἐξεπλήσσοντο λέγοντες πόθεν τούτῳ ταῦτα καὶ τίς ἡ σοφία ἡ δοθεῖσα αὐτῷ καὶ δυνάμεις τοιαῦται διὰ τῶν χειρῶν αὐτοῦ γινόμεναι',
   'kai genomenou sabbatou ērxato en tē synagōgē didaskein kai polloi akouontes exeplēssonto legontes pothen toutō tauta kai tis hē sophia hē dotheisa autō kai dynameis toiautai dia tōn cheirōn autou ginomenai',
   '''Astonished'' (exeplēssonto — struck out of their senses; the same reaction as in 1:22). ''From whence'' (pothen — from where?). They recognise both Jesus'' wisdom and his mighty works but cannot reconcile them with his known origins. ''Given unto him'' (dotheisa — given; passive: they acknowledge a divine source but stumble over the human vessel). Their questions are correct; their conclusions will be wrong.',
   NULL),
  (3, 'Is not this the carpenter, the son of Mary, the brother of James, and Joses, and of Juda, and Simon? and are not his sisters here with us? And they were offended at him.',
   'οὐχ οὗτός ἐστιν ὁ τέκτων ὁ υἱὸς Μαρίας ἀδελφὸς δὲ Ἰακώβου καὶ Ἰωσῆ καὶ Ἰούδα καὶ Σίμωνος καὶ οὐκ εἰσὶν αἱ ἀδελφαὶ αὐτοῦ ὧδε πρὸς ἡμᾶς καὶ ἐσκανδαλίζοντο ἐν αὐτῷ',
   'ouch houtos estin ho tektōn ho huios Marias adelphos de Iakōbou kai Iōsē kai Iouda kai Simōnos kai ouk eisin hai adelphai autou hōde pros hēmas kai eskandalizonto en autō',
   '''The carpenter'' (ho tektōn — the woodworker, craftsman; the only place in the Gospels where Jesus is directly called a carpenter). ''Son of Mary'' — unusual, since Jewish men were typically identified by their father. This may reflect Joseph''s death or a veiled insult about Jesus'' parentage. ''Brothers and sisters'' — siblings named and present in the community. ''Were offended'' (eskandalizonto — were scandalised, stumbled; from skandalon). Familiarity breeds contempt: they know him too well as ''one of us'' to accept him as sent from God.',
   NULL),
  (4, 'But Jesus said unto them, A prophet is not without honour, but in his own country, and among his own kin, and in his own house.',
   'καὶ ἔλεγεν αὐτοῖς ὁ Ἰησοῦς ὅτι οὐκ ἔστιν προφήτης ἄτιμος εἰ μὴ ἐν τῇ πατρίδι αὐτοῦ καὶ ἐν τοῖς συγγενέσιν αὐτοῦ καὶ ἐν τῇ οἰκίᾳ αὐτοῦ',
   'kai elegen autois ho Iēsous hoti ouk estin prophētēs atimos ei mē en tē patridi autou kai en tois syngeneusin autou kai en tē oikia autou',
   '''A prophet is not without honour'' (ouk estin prophētēs atimos — a prophet is not unhonoured). ''But in his own country, among his own kin, and in his own house'' — three concentric circles of rejection: hometown, relatives, family. Jesus identifies himself in the prophetic tradition and acknowledges the universal pattern: those closest to a prophet are often the last to accept his message.',
   NULL),
  (5, 'And he could there do no mighty work, save that he laid his hands upon a few sick folk, and healed them.',
   'καὶ οὐκ ἠδύνατο ἐκεῖ οὐδεμίαν δύναμιν ποιῆσαι εἰ μὴ ὀλίγοις ἀρρώστοις ἐπιθεὶς τὰς χεῖρας ἐθεράπευσεν',
   'kai ouk ēdynato ekei oudemian dynamin poiēsai ei mē oligois arrōstois epitheis tas cheiras etherapeusen',
   '''Could there do no mighty work'' (ouk ēdynato oudemian dynamin poiēsai — he was unable to do any powerful work). This is not a limitation of Jesus'' power but of his purpose: he will not force miracles on the unwilling. ''Save a few sick folk'' — even in Nazareth, some had faith enough for healing. The statement is extraordinary: unbelief does not eliminate Jesus'' power but restricts the context in which he chooses to exercise it.',
   'This verse presents a profound theological tension. Jesus has demonstrated power over demons, disease, death, and nature — yet in Nazareth ''he could do no mighty work.'' The limitation is moral, not metaphysical. Jesus'' miracles are signs of the kingdom, not magic tricks. They require a context of faith because they are relational acts, not mechanical forces. God does not override human freedom; he works through willing reception. Unbelief does not weaken God''s arm but closes the door through which his power enters.'),
  (6, 'And he marvelled because of their unbelief. And he went round about the villages, teaching.',
   'καὶ ἐθαύμασεν διὰ τὴν ἀπιστίαν αὐτῶν καὶ περιῆγεν τὰς κώμας κύκλῳ διδάσκων',
   'kai ethaumasen dia tēn apistian autōn kai periēgen tas kōmas kyklō didaskōn',
   '''Marvelled'' (ethaumasen — was amazed, wondered). In all the Gospels, only two things cause Jesus to marvel: the faith of a Gentile centurion (Matthew 8:10) and the unbelief of his hometown. ''Went round about the villages'' — Nazareth''s rejection does not paralyse Jesus'' ministry; he simply moves on. Teaching continues; the mission adapts.',
   NULL),
  (7, 'And he called unto him the twelve, and began to send them forth by two and two; and gave them power over unclean spirits;',
   'καὶ προσκαλεῖται τοὺς δώδεκα καὶ ἤρξατο αὐτοὺς ἀποστέλλειν δύο δύο καὶ ἐδίδου αὐτοῖς ἐξουσίαν τῶν πνευμάτων τῶν ἀκαθάρτων',
   'kai proskaleitai tous dōdeka kai ērxato autous apostellein dyo dyo kai edidou autois exousian tōn pneumatōn tōn akathartōn',
   '''Send them forth'' (apostellein — commission as apostles; the verb from which ''apostle'' derives). ''By two and two'' (dyo dyo — in pairs; for mutual encouragement, witness credibility (Deuteronomy 19:15), and safety). ''Gave them power over unclean spirits'' (edidou exousian — was giving authority; imperfect: ongoing bestowal). Jesus delegates his own authority to the Twelve, multiplying his ministry exponentially.',
   NULL),
  (8, 'And commanded them that they should take nothing for their journey, save a staff only; no scrip, no bread, no money in their purse:',
   'καὶ παρήγγειλεν αὐτοῖς ἵνα μηδὲν αἴρωσιν εἰς ὁδὸν εἰ μὴ ῥάβδον μόνον μὴ πήραν μὴ ἄρτον μὴ εἰς τὴν ζώνην χαλκόν',
   'kai parēngeilen autois hina mēden airōsin eis hodon ei mē rhabdon monon mē pēran mē arton mē eis tēn zōnēn chalkon',
   '''Take nothing'' — radical simplicity. ''Staff only'' (rhabdon monon — a walking stick, the one permitted item). ''No scrip'' (pēran — no beggar''s bag or traveller''s satchel). ''No bread'' — no provisions. ''No money'' (chalkon — no copper coins). The mission requires total dependence on God''s provision through hospitable households. Travelling light demonstrates trust and prevents the gospel from being confused with a commercial enterprise.',
   NULL),
  (9, 'But be shod with sandals; and not put on two coats.',
   'ἀλλ᾿ ὑποδεδεμένους σανδάλια καὶ μὴ ἐνδύσησθε δύο χιτῶνας',
   'all hypodedemenous sandalia kai mē endysēsthe dyo chitōnas',
   '''Sandals'' (sandalia — allowed). ''Two coats'' (dyo chitōnas — two tunics/undergarments; the inner garment worn next to the skin). One tunic is sufficient; a spare implies self-reliance. Every instruction reinforces the same principle: go simply, depend completely on God.',
   NULL),
  (10, 'And he said unto them, In what place soever ye enter into an house, there abide till ye depart from that place.',
   'καὶ ἔλεγεν αὐτοῖς ὅπου ἐὰν εἰσέλθητε εἰς οἰκίαν ἐκεῖ μένετε ἕως ἂν ἐξέλθητε ἐκεῖθεν',
   'kai elegen autois hopou ean eiselthēte eis oikian ekei menete heōs an exelthēte ekeithen',
   '''There abide'' (ekei menete — stay there). ''Till ye depart'' — remain in the first house that receives you; do not shop around for better accommodations. This instruction prevents social climbing and shows that the missionaries are not seeking comfort but accepting whatever hospitality is offered.',
   NULL),
  (11, 'And whosoever shall not receive you, nor hear you, when ye depart thence, shake off the dust under your feet for a testimony against them. Verily I say unto you, It shall be more tolerable for Sodom and Gomorrha in the day of judgment, than for that city.',
   'καὶ ὅσοι ἂν μὴ δέξωνται ὑμᾶς μηδὲ ἀκούσωσιν ὑμῶν ἐκπορευόμενοι ἐκεῖθεν ἐκτινάξατε τὸν χοῦν τὸν ὑποκάτω τῶν ποδῶν ὑμῶν εἰς μαρτύριον αὐτοῖς ἀμὴν λέγω ὑμῖν ἀνεκτότερον ἔσται Σοδόμοις ἢ Γομόρροις ἐν ἡμέρᾳ κρίσεως ἢ τῇ πόλει ἐκείνῃ',
   'kai hosoi an mē dexōntai hymas mēde akousōsin hymōn ekporeuomenoi ekeithen ektinaxate ton choun ton hypokatō tōn podōn hymōn eis martyrion autois amēn legō hymin anektoteron estai Sodomois ē Gomorrois en hēmera kriseōs ē tē polei ekeinē',
   '''Not receive you'' — rejection of the apostles equals rejection of Jesus (Luke 10:16). ''Shake off the dust'' (ektinaxate ton choun — shake out the dirt). Jews shook dust off their feet when leaving Gentile territory, symbolising complete separation. To do this in a Jewish town is a solemn prophetic act declaring that town equivalent to pagan territory. ''More tolerable for Sodom'' — the severity of judgment corresponds to the magnitude of the opportunity rejected.',
   NULL),
  (12, 'And they went out, and preached that men should repent.',
   'καὶ ἐξελθόντες ἐκήρυσσον ἵνα μετανοήσωσιν',
   'kai exelthontes ekērysson hina metanoēsōsin',
   '''Went out'' (exelthontes — they departed). ''Preached that men should repent'' (ekērysson hina metanoēsōsin — proclaimed in order that people might repent). Their message is identical to Jesus'' opening proclamation (1:15) and John the Baptist''s (1:4). The central demand of the kingdom is repentance — a complete change of mind and direction.',
   NULL),
  (13, 'And they cast out many devils, and anointed with oil many that were sick, and healed them.',
   'καὶ δαιμόνια πολλὰ ἐξέβαλλον καὶ ἤλειφον ἐλαίῳ πολλοὺς ἀρρώστους καὶ ἐθεράπευον',
   'kai daimonia polla exeballon kai ēleiphon elaiō pollous arrōstous kai etherapeuon',
   '''Cast out many devils'' — the authority Jesus gave them (v.7) works. ''Anointed with oil'' (ēleiphon elaiō — rubbed with olive oil). Oil was used both medicinally (Isaiah 1:6, Luke 10:34) and symbolically as a sign of the Spirit''s healing power (James 5:14). ''Healed them'' (etherapeuon — were healing; imperfect: continued, widespread healing). The mission is a success: the apostles extend Jesus'' ministry of word and power.',
   NULL),
  (14, 'And king Herod heard of him; (for his name was spread abroad:) and he said, That John the Baptist was risen from the dead, and therefore mighty works do shew forth themselves in him.',
   'καὶ ἤκουσεν ὁ βασιλεὺς Ἡρῴδης φανερὸν γὰρ ἐγένετο τὸ ὄνομα αὐτοῦ καὶ ἔλεγεν ὅτι Ἰωάννης ὁ βαπτίζων ἐκ νεκρῶν ἠγέρθη καὶ διὰ τοῦτο ἐνεργοῦσιν αἱ δυνάμεις ἐν αὐτῷ',
   'kai ēkousen ho basileus Hērōdēs phaneron gar egeneto to onoma autou kai elegen hoti Iōannēs ho baptizōn ek nekrōn ēgerthē kai dia touto energousin hai dynameis en autō',
   '''King Herod'' — Herod Antipas, tetrarch of Galilee and Peraea (technically not a king but often called one). ''His name was spread abroad'' — Jesus'' fame has reached the royal court. ''John the Baptist was risen from the dead'' — Herod''s guilty conscience interprets Jesus as a resurrected John. This superstitious fear reveals the power of a guilty conscience: the man he murdered haunts him.',
   NULL),
  (15, 'Others said, That it is Elias. And others said, That it is a prophet, or as one of the prophets.',
   'ἄλλοι ἔλεγον ὅτι Ἠλίας ἐστίν ἄλλοι δὲ ἔλεγον ὅτι προφήτης ἐστίν ὡς εἷς τῶν προφητῶν',
   'alloi elegon hoti Ēlias estin alloi de elegon hoti prophētēs estin hōs heis tōn prophētōn',
   '''Elias'' (Ēlias — Elijah; expected to return before the Messiah, Malachi 4:5). ''A prophet, or as one of the prophets'' — speculation about Jesus'' identity. The public debate mirrors the question the disciples will face at Caesarea Philippi (8:27-29). Everyone recognises Jesus as extraordinary; no one yet grasps the full truth.',
   NULL),
  (16, 'But when Herod heard thereof, he said, It is John, whom I beheaded: he is risen from the dead.',
   'ἀκούσας δὲ ὁ Ἡρῴδης εἶπεν ὅτι ὃν ἐγὼ ἀπεκεφάλισα Ἰωάννην οὗτός ἐστιν αὐτὸς ἠγέρθη ἐκ νεκρῶν',
   'akousas de ho Hērōdēs eipen hoti hon egō apekephalisa Iōannēn houtos estin autos ēgerthē ek nekrōn',
   '''Whom I beheaded'' (hon egō apekephalisa — whom I myself decapitated; emphatic egō: I did this). ''He is risen'' — Herod cannot escape his guilt. The emphatic ''I'' shows that he owns the deed even while fearing its consequences. Mark uses Herod''s troubled conscience as the transition into the flashback of John''s execution.',
   NULL),
  (17, 'For Herod himself had sent forth and laid hold upon John, and bound him in prison for Herodias'' sake, his brother Philip''s wife: for he had married her.',
   'αὐτὸς γὰρ ὁ Ἡρῴδης ἀποστείλας ἐκράτησεν τὸν Ἰωάννην καὶ ἔδησεν αὐτὸν ἐν φυλακῇ διὰ Ἡρῳδιάδα τὴν γυναῖκα Φιλίππου τοῦ ἀδελφοῦ αὐτοῦ ὅτι αὐτὴν ἐγάμησεν',
   'autos gar ho Hērōdēs aposteilas ekratēsen ton Iōannēn kai edēsen auton en phylakē dia Hērōdiada tēn gynaika Philippou tou adelphou autou hoti autēn egamēsen',
   '''Herod himself'' — Herod initiated the arrest. ''For Herodias'' sake'' — Herodias was the wife of Herod''s half-brother Philip. Herod Antipas had divorced his own wife to marry Herodias. John publicly condemned this adulterous, incestuous marriage (v.18), which provoked Herodias'' lethal hatred.',
   NULL),
  (18, 'For John had said unto Herod, It is not lawful for thee to have thy brother''s wife.',
   'ἔλεγεν γὰρ ὁ Ἰωάννης τῷ Ἡρῴδῃ ὅτι οὐκ ἔξεστίν σοι ἔχειν τὴν γυναῖκα τοῦ ἀδελφοῦ σου',
   'elegen gar ho Iōannēs tō Hērōdē hoti ouk exestin soi echein tēn gynaika tou adelphou sou',
   '''John had said'' (elegen — was saying; imperfect: John repeatedly told Herod). ''Not lawful'' (ouk exestin — not permitted; citing Leviticus 18:16, 20:21). John confronted the most powerful man in the region with God''s law — a prophet speaking truth to power regardless of personal cost. This courage cost him his freedom and ultimately his life.',
   NULL),
  (19, 'Therefore Herodias had a quarrel against him, and would have killed him; but she could not:',
   'ἡ δὲ Ἡρῳδιὰς ἐνεῖχεν αὐτῷ καὶ ἤθελεν αὐτὸν ἀποκτεῖναι καὶ οὐκ ἠδύνατο',
   'hē de Hērōdias eneichen autō kai ēthelen auton apokteinai kai ouk ēdynato',
   '''Had a quarrel'' (eneichen — harboured a grudge, nursed resentment). ''Would have killed him'' (ēthelen apokteinai — wanted to kill him). ''But she could not'' — Herod''s ambivalent protection of John prevented Herodias from acting. She had the desire but not the opportunity — until the banquet (v.21).',
   NULL),
  (20, 'For Herod feared John, knowing that he was a just man and an holy, and observed him; and when he heard him, he did many things, and heard him gladly.',
   'ὁ γὰρ Ἡρῴδης ἐφοβεῖτο τὸν Ἰωάννην εἰδὼς αὐτὸν ἄνδρα δίκαιον καὶ ἅγιον καὶ συνετήρει αὐτόν καὶ ἀκούσας αὐτοῦ πολλὰ ἐποίει καὶ ἡδέως αὐτοῦ ἤκουεν',
   'ho gar Hērōdēs ephobeito ton Iōannēn eidōs auton andra dikaion kai hagion kai synetērei auton kai akousas autou polla epoiei kai hēdeōs autou ēkouen',
   '''Feared John'' (ephobeito — reverenced, stood in awe). ''Just man and holy'' (andra dikaion kai hagion). ''Observed him'' (synetērei — protected, kept safe). ''Heard him gladly'' (hēdeōs ēkouen — listened to him with pleasure). Herod is a tragic figure: he recognises John''s righteousness, enjoys his preaching, even protects him — yet lacks the moral courage to obey what he hears. Herod is the classic hearer of the word who never becomes a doer (James 1:22-25).',
   NULL),
  (21, 'And when a convenient day was come, that Herod on his birthday made a supper to his lords, high captains, and chief estates of Galilee;',
   'καὶ γενομένης ἡμέρας εὐκαίρου ὅτε Ἡρῴδης τοῖς γενεσίοις αὐτοῦ δεῖπνον ἐποίει τοῖς μεγιστᾶσιν αὐτοῦ καὶ τοῖς χιλιάρχοις καὶ τοῖς πρώτοις τῆς Γαλιλαίας',
   'kai genomenēs hēmeras eukairou hote Hērōdēs tois genesiois autou deipnon epoiei tois megistanin autou kai tois chiliarchois kai tois prōtois tēs Galilaias',
   '''Convenient day'' (hēmeras eukairou — an opportune day; for Herodias, not Herod). ''Birthday'' (genesiois — birthday celebration). ''Supper'' (deipnon — a formal banquet). ''Lords, high captains, and chief estates'' — the elite of Galilean society: courtiers (megistanin), military commanders (chiliarchois, tribunes commanding a thousand soldiers), and leading citizens (prōtois). The guest list reveals Herod''s political connections.',
   NULL),
  (22, 'And when the daughter of the said Herodias came in, and danced, and pleased Herod and them that sat with him, the king said unto the damsel, Ask of me whatsoever thou wilt, and I will give it thee.',
   'καὶ εἰσελθούσης τῆς θυγατρὸς αὐτῆς τῆς Ἡρῳδιάδος καὶ ὀρχησαμένης καὶ ἀρεσάσης τῷ Ἡρῴδῃ καὶ τοῖς συνανακειμένοις εἶπεν ὁ βασιλεὺς τῷ κορασίῳ αἴτησόν με ὃ ἐὰν θέλῃς καὶ δώσω σοι',
   'kai eiselthousēs tēs thygatros autēs tēs Hērōdiados kai orchēsamenēs kai aresasēs tō Hērōdē kai tois synanakeimenois eipen ho basileus tō korasiō aitēson me ho ean thelēs kai dōsō soi',
   '''Daughter of Herodias'' — traditionally identified as Salome. ''Danced'' (orchēsamenēs — performed a dance). For a princess to dance before a banquet of drunken men was extraordinary and deliberately provocative. ''Pleased'' (aresasēs — gratified). ''Ask whatsoever thou wilt'' — a rash promise fuelled by wine, lust, and the desire to impress his guests.',
   NULL),
  (23, 'And he sware unto her, Whatsoever thou shalt ask of me, I will give it thee, unto the half of my kingdom.',
   'καὶ ὤμοσεν αὐτῇ ὅτι ὃ ἐάν με αἰτήσῃς δώσω σοι ἕως ἡμίσους τῆς βασιλείας μου',
   'kai ōmosen autē hoti ho ean me aitēsēs dōsō soi heōs hēmisous tēs basileias mou',
   '''Sware'' (ōmosen — took an oath). ''Unto the half of my kingdom'' — echoing Esther 5:3, a royal formula for an extravagant promise. Herod was not actually a king and had no kingdom to give, making the oath both grandiose and hollow. The oath binds him to a commitment he will regret.',
   NULL),
  (24, 'And she went forth, and said unto her mother, What shall I ask? And she said, The head of John the Baptist.',
   'ἡ δὲ ἐξελθοῦσα εἶπεν τῇ μητρὶ αὐτῆς τί αἰτήσωμαι ἡ δὲ εἶπεν τὴν κεφαλὴν Ἰωάννου τοῦ βαπτιστοῦ',
   'hē de exelthousa eipen tē mētri autēs ti aitēsōmai hē de eipen tēn kephalēn Iōannou tou baptistou',
   '''What shall I ask?'' — the girl consults her mother, revealing that Herodias is the puppet-master behind the scene. ''The head of John the Baptist'' — Herodias seizes her opportunity with chilling efficiency. No hesitation, no deliberation — she has been waiting for this moment. The prophet''s head is her price for a dance.',
   NULL),
  (25, 'And she came in straightway with haste unto the king, and asked, saying, I will that thou give me by and by in a charger the head of John the Baptist.',
   'καὶ εἰσελθοῦσα εὐθέως μετὰ σπουδῆς πρὸς τὸν βασιλέα ᾐτήσατο λέγουσα θέλω ἵνα μοι δῷς ἐξαυτῆς ἐπὶ πίνακι τὴν κεφαλὴν Ἰωάννου τοῦ βαπτιστοῦ',
   'kai eiselthousa eutheōs meta spoudēs pros ton basilea ētēsato legousa thelō hina moi dōs exautēs epi pinaki tēn kephalēn Iōannou tou baptistou',
   '''Straightway with haste'' — immediate, urgent. ''By and by'' (exautēs — at once, immediately). ''In a charger'' (epi pinaki — on a platter, a serving dish). The gruesome request for immediate delivery on a platter transforms the banquet from a celebration into a horror. The macabre detail — a severed head served like a dish — exposes the moral depravity of Herod''s court.',
   NULL),
  (26, 'And the king was exceeding sorry; yet for his oath''s sake, and for their sakes which sat with him, he would not reject her.',
   'καὶ περίλυπος γενόμενος ὁ βασιλεύς διὰ τοὺς ὅρκους καὶ τοὺς συνανακειμένους οὐκ ἠθέλησεν αὐτὴν ἀθετῆσαι',
   'kai perilypos genomenos ho basileus dia tous horkous kai tous synanakeimenous ouk ēthelēsen autēn athetēsai',
   '''Exceeding sorry'' (perilypos — deeply grieved; the same word used for Jesus in Gethsemane, 14:34). ''For his oath''s sake'' — trapped by his own rash promise. ''For their sakes which sat with him'' — saving face before his guests. Herod values his reputation more than John''s life. He is sorry but not sorry enough to do the right thing. Moral cowardice dressed in regret.',
   NULL),
  (27, 'And immediately the king sent an executioner, and commanded his head to be brought: and he went and beheaded him in the prison,',
   'καὶ εὐθέως ἀποστείλας ὁ βασιλεὺς σπεκουλάτωρα ἐπέταξεν ἐνεχθῆναι τὴν κεφαλὴν αὐτοῦ ὁ δὲ ἀπελθὼν ἀπεκεφάλισεν αὐτὸν ἐν τῇ φυλακῇ',
   'kai eutheōs aposteilas ho basileus spekoulatōra epetaxen enechthenai tēn kephalēn autou ho de apelthōn apekephalisen auton en tē phylakē',
   '''Executioner'' (spekoulatōra — a Latin loanword: speculator, a soldier from the bodyguard who served as executioner). ''Beheaded him in the prison'' — the deed is done swiftly and brutally. John dies alone in a dark prison cell while a drunken party continues. The greatest prophet born of women (Matthew 11:11) ends his earthly ministry in squalid obscurity.',
   NULL),
  (28, 'And brought his head in a charger, and gave it to the damsel: and the damsel gave it to her mother.',
   'καὶ ἤνεγκεν τὴν κεφαλὴν αὐτοῦ ἐπὶ πίνακι καὶ ἔδωκεν αὐτὴν τῷ κορασίῳ καὶ τὸ κοράσιον ἔδωκεν αὐτὴν τῇ μητρὶ αὐτῆς',
   'kai ēnenken tēn kephalēn autou epi pinaki kai edōken autēn tō korasiō kai to korasion edōken autēn tē mētri autēs',
   'The chain of delivery: executioner to girl to mother. The prophet''s head passes through the hands of a teenager into the hands of the woman who orchestrated his death. Mark narrates with horrifying restraint — no editorial comment, no moral outrage. The facts speak for themselves. This is what happens when political power, personal grudges, and moral cowardice converge.',
   NULL),
  (29, 'And when his disciples heard of it, they came and took up his corpse, and laid it in a tomb.',
   'καὶ ἀκούσαντες οἱ μαθηταὶ αὐτοῦ ἦλθον καὶ ἦραν τὸ πτῶμα αὐτοῦ καὶ ἔθηκαν αὐτὸ ἐν μνημείῳ',
   'kai akousantes hoi mathētai autou ēlthon kai ēran to ptōma autou kai ethēkan auto en mnēmeiō',
   '''His disciples'' — John''s disciples. ''Took up his corpse'' (ēran to ptōma — carried his body; ptōma literally means ''a fallen thing,'' a corpse). ''Laid it in a tomb'' — they perform the final act of devotion. John''s burial foreshadows Jesus'' burial (15:46). The forerunner''s death anticipates the Messiah''s death — both killed by political powers manipulated by personal vendettas.',
   NULL),
  (30, 'And the apostles gathered themselves together unto Jesus, and told him all things, both what they had done, and what they had taught.',
   'καὶ συνάγονται οἱ ἀπόστολοι πρὸς τὸν Ἰησοῦν καὶ ἀπήγγειλαν αὐτῷ πάντα καὶ ὅσα ἐποίησαν καὶ ὅσα ἐδίδαξαν',
   'kai synagontai hoi apostoloi pros ton Iēsoun kai apēngeilan autō panta kai hosa epoiēsan kai hosa edidaxan',
   '''The apostles'' (hoi apostoloi — the sent ones; the only time Mark uses this title). ''Gathered together'' — the mission teams return. ''Told him all things'' — debriefing: what they did (miracles) and what they taught (repentance). Accountability and reporting are part of apostolic ministry. They report to Jesus, not to a board or committee.',
   NULL),
  (31, 'And he said unto them, Come ye yourselves apart into a desert place, and rest a while: for there were many coming and going, and they had no leisure so much as to eat.',
   'καὶ εἶπεν αὐτοῖς δεῦτε ὑμεῖς αὐτοὶ κατ᾿ ἰδίαν εἰς ἔρημον τόπον καὶ ἀναπαύεσθε ὀλίγον ἦσαν γὰρ οἱ ἐρχόμενοι καὶ οἱ ὑπάγοντες πολλοί καὶ οὐδὲ φαγεῖν ηὐκαίρουν',
   'kai eipen autois deute hymeis autoi kat idian eis erēmon topon kai anapauesthе oligon ēsan gar hoi erchomenoi kai hoi hypagontes polloi kai oude phagein ēukairoun',
   '''Come ye yourselves apart'' (deute hymeis autoi — you yourselves come away). ''Into a desert place'' (eis erēmon topon — to a solitary, uninhabited area). ''Rest a while'' (anapauesthе oligon — refresh yourselves a little). ''They had no leisure so much as to eat'' — the same situation as 3:20. Jesus recognises his disciples'' need for rest and renewal. Ministry without retreat leads to burnout. Jesus models the rhythm of engagement and withdrawal.',
   NULL),
  (32, 'And they departed into a desert place by ship privately.',
   'καὶ ἀπῆλθον εἰς ἔρημον τόπον τῷ πλοίῳ κατ᾿ ἰδίαν',
   'kai apēlthon eis erēmon topon tō ploiō kat idian',
   '''By ship privately'' — they cross the lake by boat to find solitude. But the plan for rest will be interrupted by the crowd''s need (v.33), and Jesus will respond with compassion rather than frustration.',
   NULL),
  (33, 'And the people saw them departing, and many knew him, and ran afoot thither out of all cities, and outwent them, and came together unto him.',
   'καὶ εἶδον αὐτοὺς ὑπάγοντας καὶ ἐπέγνωσαν αὐτὸν πολλοί καὶ πεζῇ ἀπὸ πασῶν τῶν πόλεων συνέδραμον ἐκεῖ καὶ προῆλθον αὐτούς καὶ συνῆλθον πρὸς αὐτόν',
   'kai eidon autous hypagontas kai epegnōsan auton polloi kai pezē apo pasōn tōn poleōn synedramon ekei kai proēlthon autous kai synēlthon pros auton',
   '''Saw them departing'' — the crowd watches the boat''s direction. ''Ran afoot'' (pezē synedramon — on foot they ran together). ''Outwent them'' (proēlthon autous — arrived before them). The crowd runs around the northern shore of the lake and arrives at the destination before the boat. Their desperation to reach Jesus overrides all other concerns.',
   NULL),
  (34, 'And Jesus, when he came out, saw much people, and was moved with compassion toward them, because they were as sheep not having a shepherd: and he began to teach them many things.',
   'καὶ ἐξελθὼν εἶδεν ὁ Ἰησοῦς πολὺν ὄχλον καὶ ἐσπλαγχνίσθη ἐπ᾿ αὐτοῖς ὅτι ἦσαν ὡς πρόβατα μὴ ἔχοντα ποιμένα καὶ ἤρξατο διδάσκειν αὐτοὺς πολλά',
   'kai exelthōn eiden ho Iēsous polyn ochlon kai esplanchnisthē ep autois hoti ēsan hōs probata mē echonta poimena kai ērxato didaskein autous polla',
   '''Moved with compassion'' (esplanchnisthē — deeply moved in his viscera; see 1:41). ''As sheep not having a shepherd'' — echoing Numbers 27:17 and Ezekiel 34:5, where God condemns Israel''s leaders for failing to shepherd his flock. Jesus sees not a crowd but a flock — leaderless, vulnerable, needing direction. ''He began to teach them'' — the response to compassion is teaching. In Mark, the shepherd''s first act is not feeding (that comes later, vv.35-44) but teaching.',
   'This verse is theologically rich. The image of ''sheep without a shepherd'' echoes God''s promise in Ezekiel 34:23: ''I will set up one shepherd over them, and he shall feed them.'' Jesus fulfils this prophecy: he is the Good Shepherd promised by God. His compassion (splanchnizomai) is not mere emotion but divine motivation — it moves him to act. Significantly, his first response is to teach, not to heal or feed. The deepest human need is not physical but spiritual: people need the word of God before they need the bread of earth.'),
  (35, 'And when the day was now far spent, his disciples came unto him, and said, This is a desert place, and now the time is far passed:',
   'καὶ ἤδη ὥρας πολλῆς γενομένης προσελθόντες αὐτῷ οἱ μαθηταὶ αὐτοῦ λέγουσιν ὅτι ἔρημός ἐστιν ὁ τόπος καὶ ἤδη ὥρα πολλή',
   'kai ēdē hōras pollēs genomenēs proselthontes autō hoi mathētai autou legousin hoti erēmos estin ho topos kai ēdē hōra pollē',
   '''Day was far spent'' (hōras pollēs — many hours having passed; late afternoon). ''Desert place'' — the disciples state the practical problem: remote location, late hour, large crowd, no food. Their solution (v.36) is logical: dismiss the people to find food. Jesus'' solution will be supernatural.',
   NULL),
  (36, 'Send them away, that they may go into the country round about, and into the villages, and buy themselves bread: for they have nothing to eat.',
   'ἀπόλυσον αὐτούς ἵνα ἀπελθόντες εἰς τοὺς κύκλῳ ἀγροὺς καὶ κώμας ἀγοράσωσιν ἑαυτοῖς ἄρτους τί γὰρ φάγωσιν οὐκ ἔχουσιν',
   'apolyson autous hina apelthontes eis tous kyklō agrous kai kōmas agorasōsin heautois artous ti gar phagōsin ouk echousin',
   '''Send them away'' (apolyson — dismiss them). ''Buy themselves bread'' — the disciples assume the crowd must fend for itself. Their suggestion is reasonable but unimaginative. Jesus is about to teach them that when God is present, human resources are not the limiting factor.',
   NULL),
  (37, 'He answered and said unto them, Give ye them to eat. And they say unto him, Shall we go and buy two hundred pennyworth of bread, and give them to eat?',
   'ὁ δὲ ἀποκριθεὶς εἶπεν αὐτοῖς δότε αὐτοῖς ὑμεῖς φαγεῖν καὶ λέγουσιν αὐτῷ ἀπελθόντες ἀγοράσωμεν δηναρίων διακοσίων ἄρτους καὶ δῶμεν αὐτοῖς φαγεῖν',
   'ho de apokritheis eipen autois dote autois hymeis phagein kai legousin autō apelthontes agorasōmen dēnariōn diakosiōn artous kai dōmen autois phagein',
   '''Give ye them to eat'' (dote autois hymeis phagein — you yourselves give them food; emphatic: you do it). ''Two hundred pennyworth'' (dēnariōn diakosiōn — 200 denarii; about 8 months'' wages for a labourer). The disciples calculate the impossibility: they cannot possibly buy enough bread. But Jesus has not asked them to buy; he has asked them to give. The difference between the two is the gap where miracles happen.',
   NULL),
  (38, 'He saith unto them, How many loaves have ye? go and see. And when they knew, they say, Five, and two fishes.',
   'ὁ δὲ λέγει αὐτοῖς πόσους ἄρτους ἔχετε ὑπάγετε καὶ ἴδετε καὶ γνόντες λέγουσιν πέντε καὶ δύο ἰχθύας',
   'ho de legei autois posous artous echete hypagete kai idete kai gnontes legousin pente kai duo ichthyas',
   '''How many loaves have ye?'' — Jesus does not begin with the deficit but with the available resources. ''Go and see'' — take inventory. ''Five, and two fishes'' — five barley loaves (John 6:9) and two small fish. An absurdly small amount for thousands of people. But Jesus works with what is available. He does not need much; he needs what we have, offered to him.',
   NULL),
  (39, 'And he commanded them to make all sit down by companies upon the green grass.',
   'καὶ ἐπέταξεν αὐτοῖς ἀνακλῖναι πάντας συμπόσια συμπόσια ἐπὶ τῷ χλωρῷ χόρτῳ',
   'kai epetaxen autois anaklinai pantas symposia symposia epi tō chlōrō chortō',
   '''Commanded'' (epetaxen — ordered). ''By companies'' (symposia symposia — group by group; a Semitic idiom for orderly arrangement: dinner parties). ''Green grass'' (chlōrō chortō — green vegetation; a detail indicating spring, near Passover, John 6:4). The organisation is deliberate: Jesus turns a chaotic mob into an ordered assembly, a wilderness into a banquet hall.',
   NULL),
  (40, 'And they sat down in ranks, by hundreds, and by fifties.',
   'καὶ ἀνέπεσον πρασιαὶ πρασιαί ἀνὰ ἑκατὸν καὶ ἀνὰ πεντήκοντα',
   'kai anepesan prasiai prasiai ana hekaton kai ana pentēkonta',
   '''In ranks'' (prasiai prasiai — row by row; literally ''garden beds,'' referring to the orderly rectangular groups). ''By hundreds and by fifties'' — the arrangement echoes Moses'' organisation of Israel in the wilderness (Exodus 18:25). Jesus is the new Moses organising God''s people for a wilderness feast. The scene deliberately evokes the Exodus: a shepherd-leader, a wilderness, an ordered people, and miraculous bread.',
   NULL),
  (41, 'And when he had taken the five loaves and the two fishes, he looked up to heaven, and blessed, and brake the loaves, and gave them to his disciples to set before them; and the two fishes divided he among them all.',
   'καὶ λαβὼν τοὺς πέντε ἄρτους καὶ τοὺς δύο ἰχθύας ἀναβλέψας εἰς τὸν οὐρανὸν εὐλόγησεν καὶ κατέκλασεν τοὺς ἄρτους καὶ ἐδίδου τοῖς μαθηταῖς αὐτοῦ ἵνα παραθῶσιν αὐτοῖς καὶ τοὺς δύο ἰχθύας ἐμέρισεν πᾶσιν',
   'kai labōn tous pente artous kai tous duo ichthyas anablepsas eis ton ouranon eulogēsen kai kateklasen tous artous kai edidou tois mathētais autou hina parathōsin autois kai tous duo ichthyas emerisen pasin',
   '''Looked up to heaven'' (anablepsas eis ton ouranon — lifted his eyes heavenward; the posture of prayer). ''Blessed'' (eulogēsen — gave thanks, spoke a blessing). ''Brake the loaves'' (kateklasen — broke apart; the action of the host at a Jewish meal). ''Gave them to his disciples'' (edidou — was giving; imperfect: he kept giving). ''Divided among them all'' — Jesus took, blessed, broke, and gave — the four actions that will recur at the Last Supper (14:22). The disciples serve as intermediaries: Jesus provides, they distribute. The multiplication happens in Jesus'' hands.',
   NULL),
  (42, 'And they did all eat, and were filled.',
   'καὶ ἔφαγον πάντες καὶ ἐχορτάσθησαν',
   'kai ephagon pantes kai echortasthēsan',
   '''All eat'' (ephagon pantes — everyone ate). ''Were filled'' (echortasthēsan — were satisfied, fully fed; from chortazō, to feed to the full, originally used of fattening cattle). Not a meagre portion but a satisfying meal. The miracle provides abundantly — enough for all, with surplus (v.43). The God who fed Israel with manna in the wilderness now feeds a new Israel through his Son.',
   NULL),
  (43, 'And they took up twelve baskets full of the fragments, and of the fishes.',
   'καὶ ἦραν κλασμάτων δώδεκα κοφίνους πλήρεις καὶ ἀπὸ τῶν ἰχθύων',
   'kai ēran klasmatōn dōdeka kophinous plēreis kai apo tōn ichthyōn',
   '''Twelve baskets'' (dōdeka kophinous — twelve wicker baskets; the kophinos was a distinctly Jewish carrying basket). ''Full of fragments'' (klasmatōn plēreis — full of broken pieces). Twelve baskets — one for each apostle who had said ''send them away.'' The surplus is greater than the original supply. Jesus'' provision is not merely sufficient but superabundant. The number twelve may also symbolise provision for all twelve tribes of Israel.',
   NULL),
  (44, 'And they that did eat of the loaves were about five thousand men.',
   'καὶ ἦσαν οἱ φαγόντες τοὺς ἄρτους πεντακισχίλιοι ἄνδρες',
   'kai ēsan hoi phagontes tous artous pentakischilioi andres',
   '''Five thousand men'' (pentakischilioi andres — five thousand males). Matthew 14:21 adds ''beside women and children,'' suggesting the total crowd may have been 15,000-20,000. This is the only miracle (besides the resurrection) recorded in all four Gospels, emphasising its centrality. Five loaves fed five thousand — a thousand-fold multiplication.',
   NULL),
  (45, 'And straightway he constrained his disciples to get into the ship, and to go to the other side before unto Bethsaida, while he sent away the people.',
   'καὶ εὐθέως ἠνάγκασεν τοὺς μαθητὰς αὐτοῦ ἐμβῆναι εἰς τὸ πλοῖον καὶ προάγειν εἰς τὸ πέραν πρὸς Βηθσαϊδάν ἕως αὐτὸς ἀπολύσῃ τὸν ὄχλον',
   'kai eutheōs ēnagkasen tous mathētas autou embēnai eis to ploion kai proagein eis to peran pros Bēthsaidan heōs autos apolysē ton ochlon',
   '''Constrained'' (ēnagkasen — compelled, forced). ''Get into the ship'' — Jesus urgently sends the disciples ahead. John 6:15 explains why: the crowd wanted to make Jesus king by force. Jesus disperses both the crowd and the disciples to prevent a political uprising. ''While he sent away the people'' — Jesus handles the volatile crowd alone.',
   NULL),
  (46, 'And when he had sent them away, he departed into a mountain to pray.',
   'καὶ ἀποταξάμενος αὐτοῖς ἀπῆλθεν εἰς τὸ ὄρος προσεύξασθαι',
   'kai apotaxamenos autois apēlthen eis to oros proseuxasthai',
   '''Departed into a mountain to pray'' — the second major prayer scene in Mark (cf. 1:35). After the intensity of the feeding miracle and the temptation of political kingship, Jesus withdraws to pray. The mountain is a place of divine encounter (cf. Moses, Elijah). Prayer is Jesus'' response to both success and temptation.',
   NULL),
  (47, 'And when even was come, the ship was in the midst of the sea, and he alone on the land.',
   'καὶ ὀψίας γενομένης ἦν τὸ πλοῖον ἐν μέσῳ τῆς θαλάσσης καὶ αὐτὸς μόνος ἐπὶ τῆς γῆς',
   'kai opsias genomenēs ēn to ploion en mesō tēs thalassēs kai autos monos epi tēs gēs',
   '''Even was come'' (opsias genomenēs — evening arrived). ''In the midst of the sea'' — alone on the water. ''He alone on the land'' — a visual separation: the disciples struggling at sea, Jesus alone on the mountain. Yet he is watching them (v.48). The scene symbolises the church''s experience: Jesus is physically absent, the disciples are struggling, but he sees them and will come to them.',
   NULL),
  (48, 'And he saw them toiling in rowing; for the wind was contrary unto them: and about the fourth watch of the night he cometh unto them, walking upon the sea, and would have passed by them.',
   'καὶ ἰδὼν αὐτοὺς βασανιζομένους ἐν τῷ ἐλαύνειν ἦν γὰρ ὁ ἄνεμος ἐναντίος αὐτοῖς καὶ περὶ τετάρτην φυλακὴν τῆς νυκτὸς ἔρχεται πρὸς αὐτοὺς περιπατῶν ἐπὶ τῆς θαλάσσης καὶ ἤθελεν παρελθεῖν αὐτούς',
   'kai idōn autous basanizomenous en tō elaunein ēn gar ho anemos enantios autois kai peri tetartēn phylakēn tēs nyktos erchetai pros autous peripatōn epi tēs thalassēs kai ēthelen parelthein autous',
   '''Saw them'' (idōn — he saw; from the mountain, in the dark, across the water). ''Toiling'' (basanizomenous — being tormented, distressed; the same word used for torture). ''Contrary wind'' (enantios — opposing, hostile). ''Fourth watch'' (tetartēn phylakēn — 3-6 AM; the Roman division of the night). ''Walking upon the sea'' (peripatōn epi tēs thalassēs — walking on the surface of the water). ''Would have passed by them'' (ēthelen parelthein — intended to pass by; echoing the divine ''passing by'' in Exodus 33:19-22 and 1 Kings 19:11 — theophanies where God reveals himself).',
   'The phrase ''would have passed by them'' is one of the most theologically loaded in Mark. In the OT, God ''passes by'' Moses (Exodus 33:19-22) and Elijah (1 Kings 19:11) as an act of self-revelation. Jesus is not trying to avoid the disciples; he is revealing himself as Yahweh walking on the waters of chaos (Job 9:8, Psalm 77:19). The sea-walking is a theophany — a divine self-disclosure. Jesus does on the Sea of Galilee what only God does in the Old Testament: treads upon the waves.'),
  (49, 'But when they saw him walking upon the sea, they supposed it had been a spirit, and cried out:',
   'οἱ δὲ ἰδόντες αὐτὸν περιπατοῦντα ἐπὶ τῆς θαλάσσης ἔδοξαν φάντασμα εἶναι καὶ ἀνέκραξαν',
   'hoi de idontes auton peripatounta epi tēs thalassēs edoxan phantasma einai kai anekraxan',
   '''Supposed it had been a spirit'' (edoxan phantasma einai — they thought it was a ghost/apparition). ''Cried out'' (anekraxan — screamed). The disciples, already exhausted from hours of futile rowing against the wind, see a figure walking on the water in the pre-dawn darkness and are terrified. Their fear is understandable — what they are seeing is humanly impossible.',
   NULL),
  (50, 'For they all saw him, and were troubled. And immediately he talked with them, and saith unto them, Be of good cheer: it is I; be not afraid.',
   'πάντες γὰρ αὐτὸν εἶδον καὶ ἐταράχθησαν καὶ εὐθέως ἐλάλησεν μετ᾿ αὐτῶν καὶ λέγει αὐτοῖς θαρσεῖτε ἐγώ εἰμι μὴ φοβεῖσθε',
   'pantes gar auton eidon kai etarachthēsan kai eutheōs elalēsen met autōn kai legei autois tharseite egō eimi mē phobeisthe',
   '''They all saw him'' — not a private vision but a shared experience. ''Troubled'' (etarachthēsan — agitated, terrified). ''Be of good cheer'' (tharseite — take courage). ''It is I'' (egō eimi — I AM). ''Be not afraid'' (mē phobeisthe — stop being afraid). The words egō eimi echo the divine self-revelation of Exodus 3:14: ''I AM THAT I AM.'' In the OT, ''I am, do not fear'' is the characteristic speech of Yahweh appearing to his people (Isaiah 41:10, 43:1-3). Jesus identifies himself with the divine name.',
   'The phrase egō eimi (''It is I'' / ''I AM'') is the theological climax of this passage. On one level, Jesus is simply identifying himself: ''It''s me, don''t be afraid.'' On a deeper level, he is using the divine self-identification formula of Exodus 3:14 and Isaiah 43:1-3. Combined with walking on water (a divine prerogative, Job 9:8) and the ''passing by'' motif (Exodus 33:19), this is a full theophany — God revealing himself to his people in their distress. The disciples do not yet understand (v.52), but Mark wants the reader to see: the one in the boat is Yahweh in the flesh.'),
  (51, 'And he went up unto them into the ship; and the wind ceased: and they were sore amazed in themselves beyond measure, and wondered.',
   'καὶ ἀνέβη πρὸς αὐτοὺς εἰς τὸ πλοῖον καὶ ἐκόπασεν ὁ ἄνεμος καὶ λίαν ἐκ περισσοῦ ἐν ἑαυτοῖς ἐξίσταντο καὶ ἐθαύμαζον',
   'kai anebē pros autous eis to ploion kai ekopasen ho anemos kai lian ek perissou en heautois existanto kai ethaumazon',
   '''Went up into the ship'' — Jesus boards the boat. ''Wind ceased'' (ekopasen — died down, became weary; as in 4:39). ''Sore amazed beyond measure'' (lian ek perissou existanto — exceedingly, utterly out of themselves with amazement). The compound intensifiers (lian, ek perissou) indicate the most extreme astonishment recorded in Mark.',
   NULL),
  (52, 'For they considered not the miracle of the loaves: for their heart was hardened.',
   'οὐ γὰρ συνῆκαν ἐπὶ τοῖς ἄρτοις ἦν γὰρ ἡ καρδία αὐτῶν πεπωρωμένη',
   'ou gar synēkan epi tois artois ēn gar hē kardia autōn pepōrōmenē',
   '''Considered not'' (ou synēkan — did not understand; from syniēmi, to put together). ''The miracle of the loaves'' — if they had understood the feeding miracle (Jesus is the divine provider), they would not have been surprised by the sea-walking (Jesus is the divine Lord of nature). ''Their heart was hardened'' (pepōrōmenē — petrified, calloused; perfect tense: a settled condition). Mark uses the same word (pōroō) for the Pharisees in 3:5 — a startling comparison. The disciples'' spiritual perception is dangerously slow.',
   'This editorial comment by Mark is devastating. The disciples'' amazement at the sea-walking reveals their failure to comprehend the feeding miracle. The two miracles are connected: the one who multiplied bread is the one who walks on water — both are acts of the Creator God. If they had understood who fed the 5,000, they would have known who was walking toward them. ''Their heart was hardened'' uses the same word applied to Jesus'' opponents. The disciples are not hostile like the Pharisees, but they are equally slow to perceive Jesus'' true identity. Understanding comes not from seeing miracles but from perceiving who performs them.'),
  (53, 'And when they had passed over, they came into the land of Gennesaret, and drew to the shore.',
   'καὶ διαπεράσαντες ἦλθον ἐπὶ τὴν γῆν Γεννησαρὲτ καὶ προσωρμίσθησαν',
   'kai diaperasantes ēlthon epi tēn gēn Gennēsaret kai prosōrmisthēsan',
   '''Gennesaret'' — a fertile plain on the northwestern shore of the Sea of Galilee, south of Capernaum. ''Drew to the shore'' (prosōrmisthēsan — moored, anchored). The storm is over, and the boat reaches land safely — as Jesus'' word always guarantees arrival.',
   NULL),
  (54, 'And when they were come out of the ship, straightway they knew him,',
   'καὶ ἐξελθόντων αὐτῶν ἐκ τοῦ πλοίου εὐθέως ἐπιγνόντες αὐτόν',
   'kai exelthontōn autōn ek tou ploiou eutheōs epignontes auton',
   '''Straightway they knew him'' (eutheōs epignontes — immediately recognising). The people of Gennesaret recognise Jesus instantly. His fame precedes him. Unlike Nazareth, where familiarity bred contempt, this region receives him eagerly.',
   NULL),
  (55, 'And ran through that whole region round about, and began to carry about in beds those that were sick, where they heard he was.',
   'περιδραμόντες ὅλην τὴν περίχωρον ἐκείνην ἤρξαντο ἐπὶ τοῖς κραβάττοις τοὺς κακῶς ἔχοντας περιφέρειν ὅπου ἤκουον ὅτι ἐκεῖ ἐστιν',
   'peridramontes holēn tēn perichōron ekeinēn ērxanto epi tois krabattois tous kakōs echontas peripherein hopou ēkouon hoti ekei estin',
   '''Ran through'' (peridramontes — ran around, scoured the entire region). ''Carry about in beds'' (peripherein epi krabattois — carry on pallets; portable mats). ''Where they heard he was'' — the sick are brought to wherever Jesus happens to be. The region mobilises around Jesus'' presence — a spontaneous mass movement of desperation and faith.',
   NULL),
  (56, 'And whithersoever he entered, into villages, or cities, or country, they laid the sick in the streets, and besought him that they might touch if it were but the border of his garment: and as many as touched him were made whole.',
   'καὶ ὅπου ἂν εἰσεπορεύετο εἰς κώμας ἢ πόλεις ἢ ἀγροὺς ἐν ταῖς ἀγοραῖς ἐτίθουν τοὺς ἀσθενοῦντας καὶ παρεκάλουν αὐτὸν ἵνα κἂν τοῦ κρασπέδου τοῦ ἱματίου αὐτοῦ ἅψωνται καὶ ὅσοι ἂν ἥπτοντο αὐτοῦ ἐσῴζοντο',
   'kai hopou an eiseporeueto eis kōmas ē poleis ē agrous en tais agorais etithoun tous asthenountas kai parekaloun auton hina kan tou kraspedou tou himatiou autou hapsōntai kai hosoi an ēptonto autou esōzonto',
   '''Villages, cities, or country'' — everywhere without exception. ''In the streets'' (en tais agorais — in the marketplaces). ''The border of his garment'' (tou kraspedou tou himatiou — the fringe/tassel of his cloak; the tzitzit, the tassels commanded in Numbers 15:38-39). ''As many as touched him were made whole'' (hosoi ēptonto esōzonto — all who touched were healed/saved; imperfect: this kept happening, repeatedly). The chapter ends with a summary of universal healing — a counterpoint to the Nazareth rejection. Where faith receives Jesus, his power flows without limit.',
   NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Mark' AND c.chapter_number = 6;

-- Step 3: Word studies for key verses
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  -- v.3 carpenter
  ('τέκτων', 'tektōn', 'G5045', 'Carpenter, woodworker, craftsman, builder — from tiktō (to produce, create). A tektōn in first-century Galilee was a general construction worker who worked with wood, stone, and building materials. The term covers everything from furniture making to house construction. Jesus was known in Nazareth as a manual labourer — the village craftsman. This detail reveals that God incarnate spent most of his earthly life in humble, physical work. The Creator of the universe was known as ''the carpenter.'' Mark alone calls Jesus himself a tektōn; Matthew 13:55 says ''carpenter''s son.''', 1),
  -- v.5 could do no mighty work
  ('δύναμις', 'dynamis', 'G1411', 'Power, mighty work, miracle — from dynamai (to be able). In v.5, the startling phrase ''he could do no mighty work'' (oudemian dynamin poiēsai) does not mean Jesus lacked power but that his power operates within the context of faith. Miracles in Mark are not magical tricks performed for amazement but kingdom signs that require receptive hearts. The limitation is volitional, not ontological: Jesus chose not to force his power on the unwilling. God''s dynamis is not diminished by unbelief, but its expression is self-limited by divine respect for human freedom.', 2),
  -- v.34 compassion
  ('σπλαγχνίζομαι', 'splanchnizomai', 'G4697', 'To be moved with compassion — from splanchna (viscera, inner organs). This visceral compassion drives Jesus to action: he sees shepherdless sheep and responds by teaching (v.34), then feeding (vv.41-42). In Mark, splanchnizomai always precedes a mighty act: healing a leper (1:41), teaching the crowds (6:34), feeding the 4,000 (8:2). Jesus'' miracles are not demonstrations of power but responses of compassion. The divine heart feels before the divine hand acts. This word reveals the emotional interior of God incarnate.', 3),
  -- v.41 blessed
  ('εὐλογέω', 'eulogeō', 'G2127', 'To bless, speak well of, give thanks — from eu (well, good) + logos (word). Jesus ''blessed'' the five loaves and two fishes — speaking God''s goodness over the meagre provision. The blessing acknowledges God as the source of all provision and transforms the ordinary into the extraordinary. The same sequence (took, blessed, broke, gave) appears at the Last Supper (14:22), connecting the feeding miracle to the Eucharist. In both, Jesus takes what is insufficient, blesses it, and distributes abundance.', 4),
  -- v.48 walking on the sea
  ('περιπατέω', 'peripateō', 'G4043', 'To walk, walk about, conduct one''s life — from peri (around) + pateō (to tread, walk). The phrase ''walking on the sea'' (peripatōn epi tēs thalassēs) echoes Job 9:8 LXX, where God alone ''walks on the waves of the sea.'' What is God''s exclusive prerogative in the OT becomes Jesus'' action in the NT. The Sea of Galilee, which symbolises chaos and threat in Mark (4:37-39), is now beneath Jesus'' feet. He does not merely calm the chaos; he treads upon it as sovereign Lord.', 5),
  -- v.50 I AM
  ('ἐγώ εἰμι', 'egō eimi', 'G1473/G1510', 'I am — the divine self-identification formula. In ordinary Greek, egō eimi means simply ''it is I'' or ''I am he.'' But in the context of a theophany (walking on water, passing by, calming storms), the phrase echoes Exodus 3:14 (''I AM THAT I AM'') and the repeated ''I am he'' of Isaiah (41:4, 43:10, 46:4). Jesus uses egō eimi at key moments in Mark: walking on water (6:50), before the Sanhedrin (14:62). Combined with the OT sea-walking imagery, this is a divine self-revelation: the one speaking is the God of Israel in human form.', 6),
  -- v.52 hardened heart
  ('πωρόω', 'pōroō', 'G4456', 'To harden, petrify, make callous — from pōros (calcium deposit, stone). Applied to the disciples'' hearts (pepōrōmenē, perfect passive: their hearts had been hardened and remained in that state). This is the same word used for the Pharisees (3:5) and for Israel (Romans 11:7). The disciples are not hostile but obtuse — they have seen extraordinary things but have not connected them to Jesus'' identity. Hardness of heart in Mark is not intellectual inability but spiritual imperception: seeing without understanding, hearing without comprehending. It is the condition parables both diagnose and address (4:11-12).', 7),
  -- v.7 send forth / apostle
  ('ἀποστέλλω', 'apostellō', 'G649', 'To send forth, commission, dispatch on a mission — from apo (from) + stellō (to send). The noun form is apostolos (apostle, sent one). In v.7, Jesus ''began to send them forth'' (apostellein) — the verbal root of their title. An apostle is not a volunteer but one commissioned by authority greater than himself. The sending implies both the authority of the sender and the obedience of the sent. The apostles go not in their own name or power but in Jesus'', carrying his authority over unclean spirits and his message of repentance.', 8)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Mark' AND c.chapter_number = 6
  AND v.verse_number = CASE ws.word_order
    WHEN 1 THEN 3
    WHEN 2 THEN 5
    WHEN 3 THEN 34
    WHEN 4 THEN 41
    WHEN 5 THEN 48
    WHEN 6 THEN 50
    WHEN 7 THEN 52
    WHEN 8 THEN 7
  END;

-- Step 4: Cross references
INSERT INTO cross_references (verse_id, reference, ref_order)
SELECT v.id, cr.reference, cr.ref_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  -- v.3 Is not this the carpenter
  (3, 'Matthew 13:55-57', 1),
  (3, 'Luke 4:22-24', 2),
  (3, 'John 6:42', 3),
  -- v.4 prophet without honour
  (4, 'John 4:44', 4),
  -- v.5 could do no mighty work
  (5, 'Matthew 13:58', 5),
  -- v.7 sending the twelve
  (7, 'Matthew 10:1-5', 6),
  (7, 'Luke 9:1-2', 7),
  -- v.11 shake off dust
  (11, 'Acts 13:51', 8),
  (11, 'Acts 18:6', 9),
  -- v.13 anointed with oil
  (13, 'James 5:14', 10),
  -- v.14 Herod heard of him
  (14, 'Matthew 14:1-2', 11),
  (14, 'Luke 9:7-9', 12),
  -- v.18 not lawful to have brother's wife
  (18, 'Leviticus 18:16', 13),
  (18, 'Leviticus 20:21', 14),
  -- v.29 John's disciples bury him
  (29, 'Matthew 14:12', 15),
  -- v.34 sheep not having a shepherd
  (34, 'Numbers 27:17', 16),
  (34, 'Ezekiel 34:5-6', 17),
  (34, 'Ezekiel 34:23', 18),
  -- v.37 give ye them to eat
  (37, '2 Kings 4:42-44', 19),
  -- v.41 took blessed brake gave
  (41, 'Mark 14:22', 20),
  (41, '1 Corinthians 11:23-24', 21),
  -- v.44 five thousand
  (44, 'Matthew 14:21', 22),
  (44, 'Luke 9:14', 23),
  (44, 'John 6:10', 24),
  -- v.48 walking on the sea
  (48, 'Job 9:8', 25),
  (48, 'Psalm 77:19', 26),
  (48, 'Matthew 14:25-26', 27),
  -- v.50 I AM be not afraid
  (50, 'Exodus 3:14', 28),
  (50, 'Isaiah 43:1-3', 29),
  (50, 'John 6:20', 30),
  -- v.52 heart was hardened
  (52, 'Mark 8:17-21', 31),
  (52, 'Mark 3:5', 32),
  -- v.56 border of his garment
  (56, 'Mark 5:27-28', 33),
  (56, 'Numbers 15:38-39', 34),
  (56, 'Matthew 14:36', 35)
) AS cr(verse_number, reference, ref_order)
WHERE b.name = 'Mark' AND c.chapter_number = 6
  AND v.verse_number = cr.verse_number;

-- MARK CHAPTER 6 — BACKFILL (additional word_studies + cross_references)

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'πατρίδα', 'patrida', 'G3968', 'Own country/hometown — Nazareth; Mark frames the Nazareth rejection as a programmatic foil to the Gentile response that follows (5:20 Decapolis; 7:24-30 Syrophoenicia).', 100),
  (1, 'ἀκολουθοῦσιν αὐτῷ', 'akolouthousin autō', 'G190', 'Follow him — present tense; the Twelve now accompany him as a visible rabbinic band entering his hometown, intensifying the public stakes of his reception.', 101),
  (2, 'σοφία', 'sophia', 'G4678', 'Wisdom — the synagogue''s begrudging admission that his teaching displays more than local rabbinic training; wisdom tradition (Prov 8; Sir 24) signals supra-human source.', 102),
  (2, 'δυνάμεις τοιαῦται', 'dynameis toiautai', 'G1411', 'Such mighty works — plural: crowds already know of miracles elsewhere (ch.5 especially); question is how, not whether.', 103),
  (3, 'ὁ τέκτων ὁ υἱὸς τῆς Μαρίας', 'ho tektōn ho huios tēs Marias', 'G5045/G5207', 'The carpenter, son of Mary — naming Jesus only by mother (not Joseph) is unusual; may hint at early memory of virgin birth or at Joseph''s death.', 104),
  (3, 'ἐσκανδαλίζοντο', 'eskandalizonto', 'G4624', 'Were scandalised/tripped up — imperfect: ongoing stumbling; the familiar face blocks recognition of the Messiah; Isa 8:14 stone-of-stumbling theme.', 105),
  (4, 'ἄτιμος', 'atimos', 'G820', 'Without honour — alpha-privative of timē; in honour-shame culture the prophet''s own kin owe him most honour and withhold it most fiercely.', 106),
  (4, 'ἐν τῇ συγγενείᾳ', 'en tē syngeneia', 'G4772', 'Among his kindred — Mark sharpens Matthew''s form by naming relatives specifically; echoes 3:21 where his family had tried to seize him.', 107),
  (5, 'ἀρρώστοις', 'arrōstois', 'G732', 'Feeble/sickly — alpha-privative of rhōnnymi (to be strong); Mark''s delicate concession: some minor healings still happened.', 108),
  (6, 'ἐθαύμαζεν', 'ethaumazen', 'G2296', 'He marvelled — imperfect; only place in Mark where Jesus marvels at unbelief (contrast Luke 7:9 where he marvels at faith).', 109),
  (6, 'ἀπιστίαν', 'apistian', 'G570', 'Unbelief — not mere doubt but active refusal; Mark links it causally (dia tēn apistian) to the restricted works of v.5.', 110),
  (7, 'δύο δύο', 'dyo dyo', 'G1417', 'Two by two — Semitic distributive; pairs provide mutual support and meet the Deut 19:15 two-witness rule for authoritative testimony.', 111),
  (7, 'ἐξουσίαν τῶν πνευμάτων', 'exousian tōn pneumatōn', 'G1849/G4151', 'Authority over the spirits — first delegated exousia in Mark; apostolic ministry extends Jesus''s own exorcistic prerogative.', 112),
  (8, 'ῥάβδον μόνον', 'rhabdon monon', 'G4464', 'Staff only — Mark''s concession differs slightly from Matt 10:10 / Luke 9:3; the staff is pilgrim equipment (Exod 12:11), not a weapon.', 113),
  (8, 'μὴ πήραν', 'mē pēran', 'G4082', 'No travel-bag — pēra: leather knapsack; disciples travel lighter than philosophic itinerants (e.g. Cynics carried a pēra as trademark).', 114),
  (8, 'χαλκὸν εἰς τὴν ζώνην', 'chalkon eis tēn zōnēn', 'G5475/G2223', 'No copper in the belt-purse — small change stored in folded girdle; they are to depend on host hospitality, not carried currency.', 115),
  (9, 'ὑποδεδεμένους σανδάλια', 'hypodedemenous sandalia', 'G4682/G4547', 'Shod with sandals — plain sole; Mark alone permits them (Matt 10:10 forbids them); likely rural travel necessity on Galilean paths.', 116),
  (9, 'μὴ δύο χιτῶνας', 'mē dyo chitōnas', 'G1417/G5509', 'Not two tunics — one change of clothes forbidden; itinerant simplicity like John Baptist''s austerity.', 117),
  (10, 'ἐκεῖ μένετε', 'ekei menete', 'G3306', 'There remain — imperative; do not shuttle between hosts seeking better lodging; stability of residence signals respect for hospitality.', 118),
  (11, 'ἐκτινάξατε τὸν χοῦν', 'ektinaxate ton choun', 'G1621/G5522', 'Shake off the dust — rabbinic gesture for disowning pagan uncleanness; Jewish towns thus reduced to Gentile status if they reject the message.', 119),
  (11, 'εἰς μαρτύριον αὐτοῖς', 'eis martyrion autois', 'G3142', 'For a testimony against them — the gesture itself becomes evidentiary at final judgment; cf. 1:44 priestly testimony.', 120),
  (12, 'ἐκήρυσσον ἵνα μετανοῶσιν', 'ekēryssan hina metanoōsin', 'G2784/G3340', 'Preached that they should repent — imperfect + subjunctive; the apostles replicate John (1:4) and Jesus''s (1:15) kerygmatic core.', 121),
  (13, 'ἤλειφον ἐλαίῳ', 'ēleiphon elaiō', 'G218/G1637', 'Anointed with oil — imperfect; olive oil as medicinal + sacramental sign; NT foundation for Jas 5:14 elder-anointing practice.', 122),
  (14, 'ἀκουστὸν', 'akouston', 'G191', 'Heard of/known — verbal adjective; Jesus''s fame has now penetrated the Herodian court, forcing Antipas''s guilty conscience to the surface.', 123),
  (14, 'δυνάμεις ἐνεργοῦσιν', 'dynameis energousin', 'G1754', 'Miracles are at work — Herod theorises John has gained supernatural powers posthumously; eerie popular theology.', 124),
  (15, 'Ἠλίας', 'Ēlias', 'G2243', 'Elijah — Mal 4:5 expected forerunner; speculation reveals active messianic/prophetic awareness among Galileans.', 125),
  (16, 'ἀπεκεφάλισα', 'apekephalisa', 'G607', 'I beheaded — aorist; Herod''s reluctant admission in first person carries the weight of guilt: "whom I — I — beheaded".', 126),
  (17, 'Ἡρῳδιάδα', 'Hērōdiada', 'G2266', 'Herodias — Herod the Great''s granddaughter; married first to Herod II (Philip here = her husband, Josephus calls him Herod); later to Antipas.', 127),
  (18, 'οὐκ ἔξεστιν', 'ouk exestin', 'G1832', 'It is not lawful — John''s blunt halakhic pronouncement on Antipas''s marriage; Lev 18:16/20:21 prohibits union with brother''s living wife.', 128),
  (19, 'ἐνεῖχεν αὐτῷ', 'eneichen autō', 'G1758', 'Had a grudge against him — literally "held it in against him"; imperfect: nursed hatred; same verb Luke 11:53 for Pharisaic rage.', 129),
  (20, 'ἐφοβεῖτο τὸν Ἰωάννην', 'ephobeito ton Iōannēn', 'G5399', 'Feared John — imperfect; Herod''s fear is reverential dread of holy man, not political menace.', 130),
  (20, 'ἠπόρει ... ἡδέως ἤκουεν', 'ēporei ... hēdeōs ēkouen', 'G639/G2234/G191', 'Perplexed yet gladly heard — Herod''s divided mind: convicted by John''s preaching yet unable to obey; classic hardened-conscience portrait.', 131),
  (21, 'εὐκαίρου ἡμέρας', 'eukairou hēmeras', 'G2121', 'Convenient/opportune day — genitive absolute; Mark''s ironic note: the "right moment" for Herodias, not for John.', 132),
  (22, 'ὠρχήσατο', 'ōrchēsato', 'G3738', 'Danced — Salome''s solo performance before male banqueters was disgraceful by Jewish mores; Mark underscores court decadence.', 133),
  (23, 'ἕως ἡμίσους τῆς βασιλείας', 'heōs hēmisous tēs basileias', 'G2255/G932', 'Unto the half of my kingdom — Esther 5:3, 7:2 formula from Ahasuerus; Mark casts Herod as pagan-style despot, not Davidic king.', 134),
  (25, 'ἐπὶ πίνακι', 'epi pinaki', 'G4094', 'On a platter/dish — pinax: large flat serving-tray; macabre request staged as banquet course mocks prophetic martyrdom.', 135),
  (26, 'περίλυπος γενόμενος', 'perilypos genomenos', 'G4036', 'Exceeding sorry — same adjective used of Jesus in Gethsemane (14:34); Mark draws an ironic parallel.', 136),
  (26, 'οὐκ ἠθέλησεν ἀθετῆσαι', 'ouk ēthelēsen athetēsai', 'G2309/G114', 'Did not wish to reject her — Herod chose social honour of the oath over moral obligation to spare innocent life; cowardice dressed as integrity.', 137),
  (27, 'σπεκουλάτωρα', 'spekoulatora', 'G4688', 'Executioner — Latin loan speculator; originally a scout, then palace guard/headsman; Mark retains the Roman military idiom.', 138),
  (29, 'πτῶμα', 'ptōma', 'G4430', 'Corpse — literally "that which has fallen"; John''s disciples claim and bury the body, mirroring what Joseph of Arimathea will do for Jesus (15:45).', 139),
  (31, 'ἀνάπαυσαι ὀλίγον', 'anapausai oligon', 'G373', 'Rest a little — aorist middle imperative; Jesus teaches Sabbath rhythm to exhausted ministers; Jer 31:25 echo.', 140),
  (31, 'οὐδὲ φαγεῖν εὐκαίρουν', 'oude phagein eukairoun', 'G2119', 'Nor had they leisure to eat — imperfect of eukaireō; demands of crowds have eclipsed basic self-care.', 141),
  (34, 'ὡς πρόβατα μὴ ἔχοντα ποιμένα', 'hōs probata mē echonta poimena', 'G4263/G4166', 'As sheep not having a shepherd — exact LXX of Num 27:17 / 1 Kgs 22:17; Jesus fulfils Ezek 34 promise of Davidic shepherd.', 142),
  (37, 'δηναρίων διακοσίων', 'dēnariōn diakosiōn', 'G1220/G1250', 'Two hundred denarii — roughly eight months wages for a labourer; disciples assume feeding is economically impossible.', 143),
  (38, 'ὑπάγετε ἴδετε', 'hypagete idete', 'G5217/G1492', 'Go and see — double imperative; Jesus refuses to solve the problem in the abstract, forcing disciples to audit resources.', 144),
  (39, 'χλωρῷ χόρτῳ', 'chlōrō chortō', 'G5515/G5528', 'Green grass — Mark''s spring detail (Passover season, cf. John 6:4); evokes Ps 23:2 shepherd-prepared table.', 145),
  (40, 'πρασιαὶ πρασιαὶ', 'prasiai prasiai', 'G4237', 'In ranks like garden-plots — prasia: vegetable bed; the crowd''s orderly arrangement in coloured-robe groupings suggests Sinai-camp imagery (Exod 18:21).', 146),
  (41, 'ἀναβλέψας εἰς τὸν οὐρανόν', 'anablepsas eis ton ouranon', 'G308/G3772', 'Looking up to heaven — standard Jewish prayer posture; the Father is the true host and Jesus the mediating Son.', 147),
  (41, 'ἐκλάσεν', 'eklasen', 'G2806', 'Broke — aorist of klaō; the same verb Jesus will use at the Last Supper (14:22); feeding miracle prefigures Eucharistic breaking.', 148),
  (43, 'κοφίνων πληρώματα δώδεκα', 'kophinōn plērōmata dōdeka', 'G2894/G4138/G1427', 'Twelve basket-fuls — kophinos: small wicker basket associated with Jews (Juvenal Sat. 3.14); twelve basketfuls = one per tribe.', 149),
  (45, 'ἠνάγκασεν', 'ēnankasen', 'G315', 'Compelled — aorist; strong verb; John 6:15 explains: the crowd wanted to crown him king, so he forced disciples off to prevent political messianism.', 150),
  (46, 'ἀποταξάμενος αὐτοῖς', 'apotaxamenos autois', 'G657', 'Having taken leave — formal farewell; Jesus retreats to a mountain (Moses / Elijah pattern) for solitary intercession.', 151),
  (48, 'τετάρτῃ φυλακῇ τῆς νυκτὸς', 'tetartē phylakē tēs nyktos', 'G5067/G5438', 'Fourth watch — Roman reckoning: 3-6 am; disciples had rowed against headwinds roughly nine hours.', 152),
  (48, 'ἤθελεν παρελθεῖν αὐτούς', 'ēthelen parelthein autous', 'G2309/G3928', 'Would have passed them by — LXX parerchomai used of God''s theophanic "passing by" (Exod 33:19-22; 1 Kgs 19:11); divine-self-disclosure idiom.', 153),
  (49, 'φάντασμα', 'phantasma', 'G5326', 'Phantom/apparition — occurs only here and Matt 14:26 in NT; popular belief held that nocturnal ghosts walked near water.', 154),
  (50, 'θαρσεῖτε ... μὴ φοβεῖσθε', 'tharseite ... mē phobeisthe', 'G2293/G5399', 'Take courage ... stop being afraid — double imperative sandwiching egō eimi; same formula as Isa 41:10 prophetic consolation.', 155),
  (51, 'ἐξίσταντο ἐν ἑαυτοῖς', 'existanto en heautois', 'G1839', 'Were utterly amazed in themselves — imperfect; ekstasis language: pushed out of rational bearings; Mark intensifies to underscore non-comprehension.', 156),
  (53, 'Γεννησαρέτ', 'Gennēsaret', 'G1082', 'Gennesaret — fertile crescent plain NW of the lake (Josephus War 3.10.8); a densely populated agricultural district; intense miraculous ministry follows.', 157),
  (55, 'περιέδραμον ὅλην τὴν χώραν', 'periedramon holēn tēn chōran', 'G4063', 'Ran round the whole country — aorist; Mark''s hyperbolic pulse: Jesus''s reputation now sweeps Galilee''s plain at sprinting pace.', 158),
  (56, 'κράσπεδον τοῦ ἱματίου', 'kraspedon tou himatiou', 'G2899/G2440', 'Fringe/tassel of the garment — tzitzit mandated by Num 15:38-39; a rabbi''s tassels marked covenant identity; continuous with 5:28 haemorrhaging woman.', 159),
  (56, 'διεσῴζοντο', 'diesōzonto', 'G1295', 'Were thoroughly saved/healed — imperfect passive of diasōzō; sōzō semantic field: rescue, heal, save; Mark blurs physical and soteriological salvation.', 160)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Mark' AND c.chapter_number = 6 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

